mapper.select:
select id
from kb_comment
where one_id = #{oneId}

select COUNT(*)
FROM kb_comment
where user_id = #{userId}

select distinct t2.* from ( select kb.id as id,kb.title as title, kc.name as ctName,csu.real_name as createName, kbu.create_time as pubTime,kc.sw_id as swId,ku.readCount,kb.status as status from (select max(create_time) create_time, user_id, basic_id,status,is_deleted from kb_comment group by user_id,basic_id,status,is_deleted) kbu LEFT JOIN kb_basic kb on kbu.basic_id = kb.id LEFT JOIN castle_sys_user csu on kb.auth = csu.id left join kb_category kc on kb.category_id = kc.id left join kb_subject_warehouse ksw on kc.sw_id = ksw.id left join (select count(1) as readCount,b_id from kb_basic_user where type =1 GROUP BY b_id) ku on kbu.basic_id = ku.b_id where kbu.user_id = #{kbBaseShowDto.createUser} and kb.auth != #{kbBaseShowDto.createUser} and kb.status = 1 and kbu.status = 1 and kbu.is_deleted = 2 and kb.is_deleted =2
and kb.category_id in (
#{id}
)
and kc.sw_id in (
#{swId}
)
and kb.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')
union select kb.id as id,kb.title as title, kc.name as ctName,csu.real_name as createName, kbu.create_time as pubTime,kc.sw_id as swId,ku.readCount,kb.status as status from (select max(create_time) create_time, user_id, basic_id,status,is_deleted from kb_comment group by user_id,basic_id,status,is_deleted) kbu LEFT JOIN kb_basic kb on kbu.basic_id = kb.id LEFT JOIN castle_sys_user csu on kb.auth = csu.id left join kb_category kc on kb.category_id = kc.id left join kb_subject_warehouse ksw on kc.sw_id = ksw.id left join (select count(1) as readCount,b_id from kb_basic_user where type =1 GROUP BY b_id) ku on kbu.basic_id = ku.b_id where kbu.user_id = #{kbBaseShowDto.createUser} and kb.auth = #{kbBaseShowDto.createUser} and kbu.status = 1 and kbu.is_deleted = 2 and kb.is_deleted =2
and kb.category_id in (
#{id}
)
and kc.sw_id in (
#{swId}
)
and kb.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')
) t2 order by t2.pubTime desc
limit #{map.offset},#{map.rows}

