select distinct t2.* from ( select kv.id as id,kv.title as title, kc.name as ctName,csu.real_name as createName,kv.pub_time as pubTime, kc.sw_id as swId,ku.readCount,kv.status as status from (select max(create_time) create_time, user_id, basic_id,status,is_deleted from kb_comment group by user_id,basic_id,status,is_deleted) kbu LEFT JOIN kb_video kv on kbu.basic_id = kv.id LEFT JOIN castle_sys_user csu on kv.auth = csu.id left join kb_category kc on kv.category_id = kc.id left join kb_subject_warehouse ksw on kc.sw_id = ksw.id left join (select count(1) as readCount,b_id from kb_basic_user where type =1 and status =2 GROUP BY b_id) ku on kbu.basic_id = ku.b_id where kbu.user_id = #{kbBaseShowDto.createUser} and kv.auth != #{kbBaseShowDto.createUser} and kv.status = 1 and kbu.status=2 and kbu.is_deleted = 2 and kv.is_deleted =2
and kv.category_id in (
#{id}
)
and kc.sw_id in (
#{swId}
)
and kv.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')
union select kv.id as id,kv.title as title, kc.name as ctName,csu.real_name as createName,kv.pub_time as pubTime, kc.sw_id as swId,ku.readCount,kv.status as status from (select max(create_time) create_time, user_id, basic_id,status,is_deleted from kb_comment group by user_id,basic_id,status,is_deleted) kbu LEFT JOIN kb_video kv on kbu.basic_id = kv.id LEFT JOIN castle_sys_user csu on kv.auth = csu.id left join kb_category kc on kv.category_id = kc.id left join kb_subject_warehouse ksw on kc.sw_id = ksw.id left join (select count(1) as readCount,b_id from kb_basic_user where type =1 and status =2 GROUP BY b_id) ku on kbu.basic_id = ku.b_id where kbu.user_id = #{kbBaseShowDto.createUser} and kv.auth = #{kbBaseShowDto.createUser} and kbu.status=2 and kbu.is_deleted = 2 and kv.is_deleted =2
and kv.category_id in (
#{id}
)
and kc.sw_id in (
#{swId}
)
and kv.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat('%',#{kbBaseShowDto.fromTime},'%')
) t2 order by t2.pubTime desc
limit #{map.offset},#{map.rows}

